INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 7001, 0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "キャル", 0, 7);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 7002, 0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "コッコロ", 0, 7);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 7003, 0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "ペコリーヌ", 0, 7);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 10001, 0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "ペコリーヌ", 0, 10);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 10002, 0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "キャル", 0, 10);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 10003, 0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "コッコロ", 0, 10);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 10004, 0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "シェフィ", 2104010, 10);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 12001, 0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "ペコリーヌ", 0, 12);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 13001, 0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "キャル", 0, 13);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 13002, 0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "コッコロ", 0, 13);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 13003, 0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "シェフィ", 2104010, 13);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 13004, 0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "ペコリーヌ", 0, 13);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 14001, 0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "コッコロ", 0, 14);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 14002, 0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "シェフィ", 2104010, 14);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 14003, 0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "ペコリーヌ", 0, 14);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 14004, 0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "キャル", 0, 14);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 15001, 0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "コッコロ", 0, 15);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 16001, 0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "シェフィ", 2104010, 16);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 16002, 0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "ペコリーヌ", 0, 16);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 16003, 0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "キャル", 0, 16);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 16004, 0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "コッコロ", 0, 16);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 17002, 0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "コッコロ", 0, 17);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 17004, 0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "キャル", 0, 25);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 17005, 0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "コッコロ", 0, 25);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 17006, 0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "シェフィ", 2104010, 25);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 17007, 0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "ペコリーヌ", 0, 25);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 190801, 18001, 0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "カリン", 0, 18);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 2, 1, 0.0, 190801, 18002, 0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "カリン", 0, 18);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 3, 1, 0.0, 190801, 19001, 0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "カリン", 0, 19);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 4, 1, 0.0, 190801, 19002, 0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "カリン", 0, 19);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 5, 1, 0.0, 190801, 20001, 0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "カリン", 0, 20);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-470.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 6, 1, 0.0, 190801, 20002, 0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "カリン", 0, 20);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 21001, 0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "キャル", 0, 21);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 21002, 0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "コッコロ", 0, 21);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 21003, 0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "シェフィ", 2104010, 21);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 21004, 0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "ペコリーヌ", 0, 21);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 190801, 22001, 0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "カリン", 0, 22);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 2, 1, 0.0, 190801, 22002, 0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "カリン", 0, 22);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 3, 1, 0.0, 190801, 23001, 0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "カリン", 0, 23);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 4, 1, 0.0, 190801, 23002, 0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "カリン", 0, 23);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 1, 1, 4.08, 109001, 24001, 10011, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 2, 1, 5.0, 109001, 24002, 10011, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 3, 1, 10.11, 109001, 24003, 10011, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 4, 1, 4.0, 109001, 24004, 10011, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 5, 1, 6.0, 109001, 24005, 10011, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 6, 1, 0.0, 109002, 24006, 10011, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 7, 1, 0.0, 109002, 24007, 10011, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 8, 1, 0.0, 109002, 24008, 10011, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 9, 1, 0.0, 109002, 24009, 10011, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 10, 1, 0.0, 109002, 24010, 10011, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "エリコ（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 1, 1, 2.12, 109101, 24011, 10011, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 2, 5, 4.19, 109101, 24012, 10011, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 4, 3, 2, 2.3, 109101, 24013, 10011, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 4, 1, 0.0, 109102, 24014, 10011, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 5, 5, 5.23, 109101, 24015, 10011, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 6, 1, 0.0, 109102, 24016, 10011, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-385.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 8.0, 2, 7, 1, 5.01, 109101, 24017, 10011, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 8, 1, 0.0, 109102, 24018, 10011, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 9, 1, 0.0, 109102, 24019, 10011, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (0.0, "2030/12/17 14:59:59", "2019/01/31 12:00:00", 0.0, 1, 10, 1, 0.0, 109102, 24020, 10011, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "シズル（バレンタイン）", 0, 24);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 26001, 0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "シェフィ", 2104010, 26);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 26002, 0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "ペコリーヌ", 0, 26);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 26003, 0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "キャル", 0, 26);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 26004, 0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "コッコロ", 0, 26);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 2, 0.0, 106401, 27001, 0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "シェフィ", 2104010, 27);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 27002, 0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "ペコリーヌ", 0, 27);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 27003, 0, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "キャル", 0, 27);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 27004, 0, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "コッコロ", 0, 27);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 1, 1, 0.0, 190801, 28001, 0, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "カリン", 0, 28);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 2, 1, 0.0, 190801, 28002, 0, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", "カリン", 0, 28);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 3, 1, 0.0, 190801, 29001, 0, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "カリン", 0, 29);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 4, 1, 0.0, 190801, 29002, 0, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "カリン", 0, 29);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 5, 1, 0.0, 190801, 30001, 0, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", "カリン", 0, 30);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/09/24 15:00:00", 0.0, 1, 6, 1, 0.0, 190801, 30002, 0, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", "カリン", 0, 30);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/10/31 12:00:00", 0.0, 1, 7, 1, 0.0, 190801, 31001, 0, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", "カリン", 0, 31);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2030/12/17 14:59:59", "2019/10/31 12:00:00", 0.0, 1, 8, 1, 0.0, 190801, 31002, 0, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "カリン", 0, 31);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 0.0, 1, 1, 1, 0.0, 190801, 32001, 0, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "カリン", 0, 32);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 0.0, 1, 2, 1, 0.0, 190801, 32002, 0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 0, 32);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 0.0, 1, 3, 1, 0.0, 190801, 33001, 0, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", "カリン", 0, 33);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/04 4:59:59", "2019/12/20 5:00:00", 0.0, 1, 4, 1, 0.0, 190801, 33002, 0, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "カリン", 0, 33);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/10 11:59:59", "2020/01/04 5:00:00", 0.0, 1, 5, 1, 0.0, 190801, 34001, 0, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "カリン", 0, 34);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-409.0, "2020/01/10 11:59:59", "2020/01/04 5:00:00", 0.0, 1, 6, 1, 0.0, 190801, 34002, 0, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "カリン", 0, 34);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 2, 1, 1, 5.3, 105801, 38001, 0, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "ペコリーヌ", 0, 38);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-458.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 2, 2, 1, 6.5, 105801, 38002, 0, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "ペコリーヌ", 0, 38);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (9999.0, "2020/04/08 23:59:59", "2020/04/01", 9999.0, 3, 0, 3, 0.0, 105801, 39005, 0, "", "ペコリーヌ", 0, 39);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-430.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 2, 1, 0.0, 190801, 40001, 0, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "カリン", 0, 40);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106401, 41001, 0, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "シェフィ", 2104010, 41);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 41002, 0, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "ペコリーヌ", 0, 41);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 41003, 0, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "キャル", 0, 41);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 41004, 0, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "コッコロ", 0, 41);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 42001, 0, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "コッコロ", 0, 42);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106401, 42002, 0, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "シェフィ", 2104010, 42);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 42003, 0, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "ペコリーヌ", 0, 42);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 42004, 0, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "キャル", 0, 42);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105801, 43001, 0, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "ペコリーヌ", 0, 43);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 105901, 43002, 0, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "コッコロ", 0, 43);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-363.0, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 106001, 43003, 0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "キャル", 0, 43);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 123001, 43004, 0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "アメス", 0, 44);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 2, 1, 0.0, 123001, 43005, 0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "アメス", 0, 44);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 2, 3, 1, 5.79, 123001, 43006, 0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "アメス", 0, 45);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-371.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 1, 1, 1, 0.0, 123001, 46001, 0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "アメス", 0, 46);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 2, 1, 2, 0.0, 104901, 47001, 0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "シズル", 0, 47);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES (-416.5, "2030/12/17 14:59:59", "2015/12/17 15:00:00", 0.0, 2, 1, 1, 9.32, 101101, 47002, 0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "リノ", 0, 47);
